import org.apache.nifi.dbcp.DBCPService

def flowFile = session.get()
if (!flowFile) return

def db     = flowFile.getAttribute('TARGET_DATABASE')
def schema = flowFile.getAttribute('TARGET_SCHEMA')
def table  = flowFile.getAttribute('TARGET_TABLE')
def stage  = flowFile.getAttribute('TARGET_STAGE')
def fname  = flowFile.getAttribute('FILENAME')

def dbcpService = context.getProperty('Database Connection Pooling Service')
    .asControllerService(DBCPService.class)

def conn
try {
    conn = dbcpService.getConnection()
    def headerSql = "SELECT \$1 FROM @${db}.${schema}.${stage}/${fname} (FILE_FORMAT => 'MEDALLION_DW.ADMIN.CSV_RAW_FMT') LIMIT 1"
    def rs = conn.createStatement().executeQuery(headerSql)
    if (!rs.next()) throw new RuntimeException('Stage file is empty')
    def header = rs.getString(1)
    rs.close()
    def colNames = header.split(',').collect { it.trim().replaceAll('"', '') }
    // Add a FILENAME lineage column ONLY if the CSV header doesn't already have one
    // (some sources already carry FILENAME; a duplicate column would break CREATE).
    def hasFilename = colNames.any { it.equalsIgnoreCase('FILENAME') }
    def colDefs = colNames.collect { '"' + it + '" VARCHAR' }
    if (!hasFilename) colDefs.add('"FILENAME" VARCHAR')
    conn.createStatement().execute("CREATE OR REPLACE TABLE ${db}.${schema}.${table} (" + colDefs.join(', ') + ")")
    // matching transform COPY: data cols positional; add METADATA\$FILENAME -> FILENAME when we added it
    def n = colNames.size()
    def selectCols = (1..n).collect { '$' + it }
    def intoCols = colNames.collect { '"' + it + '"' }
    if (!hasFilename) {
        selectCols.add('METADATA$FILENAME')
        intoCols.add('"FILENAME"')
    }
    def copySql = "COPY INTO ${db}.${schema}.${table} (" + intoCols.join(', ') +
                  ") FROM (SELECT " + selectCols.join(', ') +
                  " FROM @${db}.${schema}.${stage}/${fname} (FILE_FORMAT => 'MEDALLION_DW.ADMIN.CSV_COPY_FMT'))" +
                  " FORCE = TRUE ON_ERROR = ABORT_STATEMENT"
    flowFile = session.putAttribute(flowFile, 'BRONZE_COPY_SQL', copySql)
    session.transfer(flowFile, REL_SUCCESS)
} catch (e) {
    log.error('CreateBronzeTable failed', e)
    flowFile = session.putAttribute(flowFile, 'create.bronze.error', e.getMessage() ?: e.toString())
    session.transfer(flowFile, REL_FAILURE)
} finally {
    conn?.close()
}
